{
  "name": "DirectDJ",
  "description": "Uma plataforma premium para contratação de DJs em Angola, conectando realizadores de eventos aos melhores talentos musicais com segurança e praticidade.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type UserRole = 'client' | 'dj' | 'admin';

export interface DJProfile {
  id: string;
  fullName: string;
  artisticName: string;
  idNumber: string;
  phoneNumber: string;
  iban: string;
  hasSoundGear: boolean;
  professionalCardUrl?: string;
  gearImageUrl?: string;
  status: 'pending' | 'approved' | 'rejected';
  rating: number;
}

export interface BookingRequest {
  id: string;
  clientId: string;
  eventType: string;
  needsGear: boolean;
  province: string;
  municipality: string;
  price: number;
  date: string;
  status: 'pending' | 'paid' | 'completed';
  commission: number;
  netAmount: number;
}

export interface AppState {
  currentUser: { email: string; role: UserRole } | null;
  djs: DJProfile[];
  bookings: BookingRequest[];
}

export enum EventType {
  Aniversario = 'Aniversário',
  Noivado = 'Pedido de Noivado',
  Casamento = 'Casamento',
  Festival = 'Festival',
  Bar = 'Bar de Rua',
  Discoteca = 'Discoteca',
  Corporativo = 'Evento Corporativo',
  Outro = 'Outro'
}

import React from 'react';

