import { DJProfile, BookingRequest, AppState } from '../types';

const STORAGE_KEY = 'directdj_state';

const initialState: AppState = {
  currentUser: null,
  djs: [
    {
      id: '1',
      fullName: 'António Mwila',
      artisticName: 'DJ Mwila',
      idNumber: '001234567LA045',
      phoneNumber: '923000111',
      iban: 'AO06000000000000000001',
      hasSoundGear: true,
      status: 'approved',
      rating: 4.8
    }
  ],
  bookings: []
};

export const getAppState = (): AppState => {
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : initialState;
};

export const saveAppState = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

import React, { useState } from 'react';
import { ArrowLeft, Upload, CheckCircle2 } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';
import { DJProfile } from '../types';

interface DJRegisterProps {
  onBack: () => void;
}

export const DJRegister: React.FC<DJRegisterProps> = ({ onBack }) => {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    fullName: '',
    artisticName: '',
    idNumber: '',
    phoneNumber: '',
    iban: '',
    hasSoundGear: false
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const state = getAppState();
    const newDJ: DJProfile = {
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
      status: 'pending',
      rating: 0
    };
    state.djs.push(newDJ);
    saveAppState(state);
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="glass p-12 rounded-3xl max-w-md w-full text-center space-y-6">
          <CheckCircle2 className="w-20 h-20 text-green-500 mx-auto" />
          <h2 className="text-3xl font-bold">Candidatura Enviada!</h2>
          <p className="text-white/60">A nossa equipa administrativa irá analisar os seus documentos. Receberá uma notificação via telefone em breve.</p>
          <button onClick={onBack} className="w-full py-4 gradient-bg rounded-xl font-bold">Voltar ao Início</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen p-6 max-w-2xl mx-auto">
      <button onClick={onBack} className="flex items-center gap-2 text-white/60 hover:text-white mb-8">
        <ArrowLeft size={20} /> Voltar
      </button>

      <div className="mb-10 text-center">
        <Logo className="justify-center mb-6" size={60} />
        <h1 className="text-3xl font-bold">Torne-se um DJ Oficial</h1>
        <p className="text-white/60">Registe o seu perfil profissional hoje.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6 glass p-8 rounded-3xl border border-white/10">
        <div className="grid md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Nome Completo</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500" 
              value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Nome Artístico</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value})} />
          </div>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Bilhete de Identidade (Nº BI)</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.idNumber} onChange={e => setFormData({...formData, idNumber: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Telefone</label>
            <input required type="tel" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.phoneNumber} onChange={e => setFormData({...formData, phoneNumber: e.target.value})} />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-white/60">IBAN para Recebimento</label>
          <input required placeholder="AO06..." className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 font-mono"
            value={formData.iban} onChange={e => setFormData({...formData, iban: e.target.value})} />
        </div>

        <div className="space-y-4 pt-4">
          <h3 className="font-bold border-b border-white/10 pb-2">Documentação</h3>

          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Carteira Profissional (PDF/PNG)</label>
            <div className="relative border-2 border-dashed border-white/10 rounded-xl p-8 text-center hover:bg-white/5 transition-colors cursor-pointer group">
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept=".pdf,.png" />
              <Upload className="mx-auto mb-2 text-white/40 group-hover:text-white" />
              <p className="text-xs text-white/40">Clique para anexar documento</p>
            </div>
          </div>

          <div className="flex items-center gap-3 bg-white/5 p-4 rounded-xl">
            <input type="checkbox" id="gear" className="w-5 h-5 rounded accent-sky-500" 
              checked={formData.hasSoundGear} onChange={e => setFormData({...formData, hasSoundGear: e.target.checked})} />
            <label htmlFor="gear" className="text-sm font-medium cursor-pointer">Possuo material de som próprio</label>
          </div>

          {formData.hasSoundGear && (
            <div className="space-y-2">
              <label className="text-sm font-medium text-white/60">Imagem do Material de Som</label>
              <div className="relative border-2 border-dashed border-white/10 rounded-xl p-8 text-center hover:bg-white/5 transition-colors cursor-pointer group">
                <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" />
                <Upload className="mx-auto mb-2 text-white/40 group-hover:text-white" />
                <p className="text-xs text-white/40">Clique para enviar imagem</p>
              </div>
            </div>
          )}
        </div>

        <button type="submit" className="w-full py-4 gradient-bg rounded-xl font-bold text-lg shadow-xl shadow-pink-500/20 active:scale-95 transition-transform mt-8">
          Submeter Registo
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard, Users, CreditCard, LogOut, Check, X, ShieldAlert } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';

interface AdminDashboardProps {
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'djs' | 'bookings'>('djs');
  const [state, setState] = useState(getAppState());

  const handleApproveDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'approved';
    saveAppState(newState);
    setState(newState);
  };

  const totalRevenue = state.bookings.reduce((acc, b) => acc + b.commission, 0);

  return (
    <div className="min-h-screen flex">
      {/* Sidebar */}
      <aside className="w-72 border-r border-white/10 glass p-8 flex flex-col">
        <Logo size={32} className="mb-12" />

        <nav className="space-y-2 flex-1">
          <button 
            onClick={() => setActiveTab('djs')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'djs' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <Users size={20} /> DJs Registados
          </button>
          <button 
            onClick={() => setActiveTab('bookings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'bookings' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <LayoutDashboard size={20} /> Reservas
          </button>
        </nav>

        <div className="pt-8 mt-auto border-t border-white/10">
          <div className="p-4 rounded-xl bg-green-500/10 border border-green-500/20 mb-6">
            <p className="text-xs text-green-200/60 uppercase font-bold tracking-wider mb-1">Comissões Acumuladas</p>
            <p className="text-xl font-black text-green-400">{totalRevenue.toLocaleString('pt-AO')} Akz</p>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-red-400 hover:bg-red-400/10 rounded-xl transition-all font-bold">
            <LogOut size={20} /> Sair
          </button>
        </div>
      </aside>

      {/* Content */}
      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-center mb-12">
          <h1 className="text-3xl font-black">
            {activeTab === 'djs' ? 'Gestão de DJs' : 'Relatório de Reservas'}
          </h1>
          <div className="flex items-center gap-4 bg-white/5 px-4 py-2 rounded-full border border-white/10 text-xs">
            <ShieldAlert size={14} className="text-orange-400" />
            Painel de Segurança Activo
          </div>
        </header>

        {activeTab === 'djs' && (
          <div className="grid gap-6">
            {state.djs.map(dj => (
              <div key={dj.id} className="glass p-6 rounded-2xl border border-white/10 flex items-center justify-between">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 rounded-full gradient-bg flex items-center justify-center font-bold text-xl">
                    {dj.artisticName[0]}
                  </div>
                  <div>
                    <h3 className="font-bold text-lg">{dj.artisticName}</h3>
                    <p className="text-sm text-white/40">{dj.fullName}</p>
                    <div className="flex gap-4 mt-1">
                      <span className="text-xs px-2 py-0.5 rounded bg-white/5 border border-white/10">BI: {dj.idNumber}</span>
                      <span className="text-xs px-2 py-0.5 rounded bg-white/5 border border-white/10">Tel: {dj.phoneNumber}</span>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-8">
                  <div className="text-right">
                    <p className="text-xs text-white/40">Equipamento</p>
                    <p className="text-sm font-bold">{dj.hasSoundGear ? 'Sim' : 'Não'}</p>
                  </div>
                  <div className="text-right min-w-[120px]">
                    <p className="text-xs text-white/40">Status</p>
                    <span className={`text-xs font-black uppercase ${dj.status === 'approved' ? 'text-green-400' : 'text-orange-400'}`}>
                      {dj.status}
                    </span>
                  </div>
                  {dj.status === 'pending' && (
                    <div className="flex gap-2">
                      <button onClick={() => handleApproveDJ(dj.id)} className="p-3 bg-green-500/20 text-green-500 rounded-xl hover:bg-green-500 hover:text-white transition-all">
                        <Check size={20} />
                      </button>
                      <button className="p-3 bg-red-500/20 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                        <X size={20} />
                      </button>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'bookings' && (
          <div className="space-y-4">
            <div className="glass rounded-2xl border border-white/10 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-white/5 text-xs font-bold uppercase tracking-wider text-white/40">
                  <tr>
                    <th className="px-6 py-4">Evento</th>
                    <th className="px-6 py-4">Local</th>
                    <th className="px-6 py-4">Total (Akz)</th>
                    <th className="px-6 py-4">Lucro App (10%)</th>
                    <th className="px-6 py-4">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/10">
                  {state.bookings.map(booking => (
                    <tr key={booking.id} className="text-sm hover:bg-white/5 transition-colors">
                      <td className="px-6 py-4 font-bold">{booking.eventType}</td>
                      <td className="px-6 py-4 text-white/60">{booking.municipality}, {booking.province}</td>
                      <td className="px-6 py-4 font-mono font-bold text-sky-400">{booking.price.toLocaleString()}</td>
                      <td className="px-6 py-4 font-mono font-bold text-green-400">{booking.commission.toLocaleString()}</td>
                      <td className="px-6 py-4">
                        <span className="px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs font-bold">PAGO</span>
                      </td>
                    </tr>
                  ))}
                  {state.bookings.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-white/20 italic">
                        Nenhuma reserva registada até ao momento.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { Home } from './views/Home';
import { DJRegister } from './views/DJRegister';
import { ClientRequest } from './views/ClientRequest';
import { AdminDashboard } from './views/AdminDashboard';
import { Shield } from 'lucide-react';

type View = 'home' | 'register-dj' | 'request-dj' | 'admin-login' | 'admin-dashboard';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [adminAuth, setAdminAuth] = useState({ email: '', password: '' });

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Simulating admin credentials from prompt
    if (adminAuth.email === 'admin@directdj.ao' && adminAuth.password === 'direct2024') {
      setCurrentView('admin-dashboard');
    } else {
      alert('Credenciais inválidas. Contacte o suporte técnico.');
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'home':
        return <Home onNavigate={setCurrentView as any} />;
      case 'register-dj':
        return <DJRegister onBack={() => setCurrentView('home')} />;
      case 'request-dj':
        return <ClientRequest onBack={() => setCurrentView('home')} />;
      case 'admin-login':
        return (
          <div className="min-h-screen flex items-center justify-center p-6 bg-black/40">
            <div className="glass p-10 rounded-3xl max-w-md w-full border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-8">
                <div className="w-16 h-16 rounded-2xl bg-orange-500/20 flex items-center justify-center mb-4">
                  <Shield size={32} className="text-orange-500" />
                </div>
                <h1 className="text-2xl font-black">Acesso Restrito</h1>
                <p className="text-sm text-white/40">Apenas para administradores DirectDJ</p>
              </div>
              <form onSubmit={handleAdminLogin} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/60 uppercase">E-mail</label>
                  <input 
                    type="email" 
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-orange-500"
                    placeholder="admin@directdj.ao"
                    value={adminAuth.email}
                    onChange={e => setAdminAuth({...adminAuth, email: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/60 uppercase">Palavra-passe</label>
                  <input 
                    type="password" 
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-orange-500"
                    placeholder="••••••••"
                    value={adminAuth.password}
                    onChange={e => setAdminAuth({...adminAuth, password: e.target.value})}
                  />
                </div>
                <div className="pt-4 space-y-4">
                  <button type="submit" className="w-full py-4 bg-orange-600 rounded-xl font-bold hover:bg-orange-500 transition-colors shadow-lg shadow-orange-600/20">
                    Entrar no Painel
                  </button>
                  <button 
                    type="button"
                    onClick={() => setCurrentView('home')} 
                    className="w-full text-sm text-white/40 hover:text-white transition-colors">
                    Voltar para o site
                  </button>
                </div>
              </form>
            </div>
          </div>
        );
      case 'admin-dashboard':
        return <AdminDashboard onLogout={() => setCurrentView('home')} />;
      default:
        return <Home onNavigate={setCurrentView as any} />;
    }
  };

  return (
    <div className="relative overflow-x-hidden min-h-screen bg-neutral-950 text-white selection:bg-pink-500/30">
      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none -z-10">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-pink-600/10 blur-[120px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-sky-600/10 blur-[120px] rounded-full"></div>
      </div>

      {renderView()}
    </div>
  );
};

export default App;

