import React, { useState, useMemo } from 'react';
import { LayoutDashboard, Users, CreditCard, LogOut, Check, X, ShieldAlert, Search, Filter } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';

interface AdminDashboardProps {
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'djs' | 'bookings'>('djs');
  const [state, setState] = useState(getAppState());

  // Filter states
  const [filterArtisticName, setFilterArtisticName] = useState('');
  const [filterFullName, setFilterFullName] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'pending' | 'approved' | 'rejected'>('all');

  const handleApproveDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'approved';
    saveAppState(newState);
    setState(newState);
  };

  const handleRejectDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'rejected';
    saveAppState(newState);
    setState(newState);
  };

  const filteredDJs = useMemo(() => {
    return state.djs.filter(dj => {
      const matchesArtistic = dj.artisticName.toLowerCase().includes(filterArtisticName.toLowerCase());
      const matchesFull = dj.fullName.toLowerCase().includes(filterFullName.toLowerCase());
      const matchesStatus = filterStatus === 'all' || dj.status === filterStatus;
      return matchesArtistic && matchesFull && matchesStatus;
    });
  }, [state.djs, filterArtisticName, filterFullName, filterStatus]);

  const totalRevenue = state.bookings.reduce((acc, b) => acc + b.commission, 0);

  return (
    <div className="min-h-screen flex">
      {/* Sidebar */}
      <aside className="w-72 border-r border-white/10 glass p-8 flex flex-col sticky top-0 h-screen">
        <Logo size={32} className="mb-12" />

        <nav className="space-y-2 flex-1">
          <button 
            onClick={() => setActiveTab('djs')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'djs' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <Users size={20} /> DJs Registados
          </button>
          <button 
            onClick={() => setActiveTab('bookings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'bookings' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <LayoutDashboard size={20} /> Reservas
          </button>
