                </div>
                <p className="text-sm text-white/60 leading-relaxed">
                  A nossa equipa administrativa leva geralmente <span className="text-white font-bold">24h a 48h úteis</span> para processar novos registos.
                </p>
                <div className="flex items-center gap-3 text-xs text-white/40 bg-black/20 p-3 rounded-lg">
                  <PhoneCall size={14} />
                  <span>Entraremos em contacto pelo: {formData.phoneNumber}</span>
                </div>
              </div>
              <div className="pt-2">
                <p className="text-[10px] uppercase font-bold text-white/30 tracking-widest mb-2">Dúvidas?</p>
                <p className="text-xs text-white/50">suporte@directdj.ao</p>
              </div>
            </div>
          </div>

          <div className="pt-4">
            <button 
              onClick={onBack} 
              className="w-full py-5 gradient-bg rounded-2xl font-black text-lg shadow-xl shadow-pink-500/20 active:scale-95 transition-all"
            >
              Voltar à Página Principal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen p-6 max-w-2xl mx-auto">
      <button onClick={onBack} className="flex items-center gap-2 text-white/60 hover:text-white mb-8">
