              value={formData.iban} 
              onChange={handleIBANChange}
              maxLength={25}
            />
            {errors.iban && (
              <div className="flex items-center gap-1 mt-2 text-red-400 text-xs animate-in slide-in-from-top-1">
                <AlertCircle size={12} />
                <span>{errors.iban}</span>
              </div>
            )}
            {!errors.iban && formData.iban.length === 25 && (
              <div className="flex items-center gap-1 mt-2 text-green-400 text-xs">
                <CheckCircle2 size={12} />
                <span>Formato de IBAN válido.</span>
              </div>
            )}
          </div>
          <p className="text-[10px] text-white/30 italic mt-1">
            Exemplo: AO06 0000 0000 0000 0000 0000 0
          </p>
        </div>

        <div className="space-y-4 pt-4">
