            <p className="text-xs text-green-200/60 uppercase font-bold tracking-wider mb-1">Lucro no Período</p>
            <p className="text-xl font-black text-green-400">{totalCommission.toLocaleString('pt-AO')} Akz</p>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-red-400 hover:bg-red-400/10 rounded-xl transition-all font-bold">
            <LogOut size={20} /> Sair
          </button>
        </div>
      </aside>

      {/* Content */}
      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-center mb-12">
          <h1 className="text-3xl font-black">
            {activeTab === 'djs' ? 'Gestão de DJs' : 'Controlo Financeiro'}
          </h1>
          <div className="flex items-center gap-4 bg-white/5 px-4 py-2 rounded-full border border-white/10 text-xs">
            <ShieldAlert size={14} className="text-orange-400" />
            Painel de Segurança Activo
          </div>
        </header>

        {activeTab === 'djs' && (
          <div className="space-y-8">
            {/* Filter Bar */}
            <div className="glass p-6 rounded-2xl border border-white/10 grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Search size={12} /> Nome Artístico
                </label>
                <input 
                  type="text"
                  placeholder="Pesquisar..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterArtisticName}
                  onChange={(e) => setFilterArtisticName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Search size={12} /> Nome Completo
                </label>
                <input 
                  type="text"
                  placeholder="Pesquisar..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterFullName}
                  onChange={(e) => setFilterFullName(e.target.value)}
