              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Filter size={12} /> Status
                </label>
                <select 
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value as any)}
                >
                  <option value="all" className="bg-neutral-900">Todos os Status</option>
                  <option value="pending" className="bg-neutral-900">Pendentes</option>
                  <option value="approved" className="bg-neutral-900">Aprovados</option>
                  <option value="rejected" className="bg-neutral-900">Rejeitados</option>
                </select>
              </div>
            </div>

            {/* List */}
            <div className="grid gap-4">
              {filteredDJs.length > 0 ? (
                filteredDJs.map(dj => (
                  <div key={dj.id} className="glass p-6 rounded-2xl border border-white/10 flex items-center justify-between group hover:border-white/20 transition-all">
                    <div className="flex items-center gap-6">
                      <div className="w-14 h-14 rounded-full gradient-bg flex items-center justify-center font-bold text-xl shadow-lg">
