                          dj.status === 'approved' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 
                          dj.status === 'pending' ? 'bg-orange-500/10 text-orange-400 border border-orange-500/20' :
                          'bg-red-500/10 text-red-400 border border-red-500/20'
