                          {dj.status === 'approved' ? 'Aprovado' : dj.status === 'pending' ? 'Pendente' : 'Rejeitado'}
                        </span>
                      </div>
                      <div className="flex gap-2 min-w-[120px] justify-end">
                        {dj.status === 'pending' && (
