              <div className="glass p-6 rounded-3xl border border-white/10 bg-green-500/5">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-green-500/20 rounded-2xl text-green-400">
                    <PieChart size={24} />
                  </div>
                  <span className="text-[10px] font-bold text-green-400 bg-green-400/10 px-2 py-1 rounded-full">COMISSÕES (10%)</span>
                </div>
                <h3 className="text-2xl font-black text-white">{totalCommission.toLocaleString('pt-AO')} Akz</h3>
                <p className="text-xs text-white/40 mt-1">Lucro bruto no período</p>
              </div>

              <div className="glass p-6 rounded-3xl border border-white/10 bg-purple-500/5">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-purple-500/20 rounded-2xl text-purple-400">
                    <DollarSign size={24} />
                  </div>
                  <span className="text-[10px] font-bold text-purple-400 bg-purple-400/10 px-2 py-1 rounded-full">PAGO AOS DJs</span>
                </div>
                <h3 className="text-2xl font-black text-white">{totalDJPayout.toLocaleString('pt-AO')} Akz</h3>
                <p className="text-xs text-white/40 mt-1">Líquido no período</p>
              </div>
            </div>

            {/* Filters Section */}
            <div className="glass p-6 rounded-3xl border border-white/10 space-y-6">
              <div className="flex flex-col md:flex-row gap-6">
                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Search size={12} /> Pesquisa Geral
                  </label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20" size={14} />
                    <input 
                      type="text" 
                      placeholder="Evento, província ou município..."
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                      value={financeSearch}
                      onChange={(e) => setFinanceSearch(e.target.value)}
                    />
                  </div>
                </div>

                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Calendar size={12} /> Data Inicial
                  </label>
                  <input 
                    type="date"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                  />
                </div>

                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Calendar size={12} /> Data Final
                  </label>
                  <input 
                    type="date"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                  />
                </div>

                {(startDate || endDate || financeSearch) && (
                  <div className="flex items-end">
                    <button 
                      onClick={() => { setStartDate(''); setEndDate(''); setFinanceSearch(''); }}
                      className="px-4 py-2 text-[10px] font-bold text-white/40 hover:text-white transition-colors flex items-center gap-2 border border-white/10 rounded-xl bg-white/5 mb-0.5"
                    >
                      <X size={12} /> LIMPAR FILTROS
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* History Table */}
            <div className="space-y-4">
              <div className="flex justify-between items-center px-2">
                <div className="flex items-center gap-4">
                  <h2 className="text-xl font-bold">Histórico de Transações</h2>
                  <p className="text-xs text-white/40">Mostrando {filteredBookings.length} transações</p>
                </div>
                <button 
                  onClick={exportToCSV}
                  disabled={filteredBookings.length === 0}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold text-xs transition-all border border-sky-500/30 bg-sky-500/10 text-sky-400 hover:bg-sky-500 hover:text-white shadow-lg shadow-sky-500/10 ${filteredBookings.length === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'active:scale-95'}`}
                >
                  <Download size={14} /> EXPORTAR CSV
                </button>
              </div>

              <div className="glass rounded-2xl border border-white/10 overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-white/5 text-[10px] font-bold uppercase tracking-wider text-white/40 border-b border-white/10">
                    <tr>
                      <th className="px-6 py-5">Data</th>
                      <th className="px-6 py-5">Evento & Local</th>
                      <th className="px-6 py-5">Valor Bruto</th>
                      <th className="px-6 py-5">Comissão (10%)</th>
                      <th className="px-6 py-5">Líquido DJ</th>
                      <th className="px-6 py-5 text-right">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/10">
                    {filteredBookings.length > 0 ? (
                      filteredBookings.map(booking => (
                        <tr key={booking.id} className="text-sm hover:bg-white/5 transition-colors group">
                          <td className="px-6 py-4">
                            <p className="font-mono text-[10px] text-white/60">{booking.date}</p>
                            <p className="font-mono text-[10px] text-white/20">Ref: #{booking.id}</p>
                          </td>
                          <td className="px-6 py-4">
                            <p className="font-bold text-white">{booking.eventType}</p>
                            <p className="text-[10px] text-white/40">{booking.municipality}, {booking.province}</p>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-white">
                            {booking.price.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-green-400">
                            {booking.commission.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-sky-400">
                            {booking.netAmount.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-green-500/10 text-green-400 rounded-full text-[10px] font-bold uppercase tracking-wider border border-green-500/20">
