          </div>
        )}
      </main>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { LayoutDashboard, Users, CreditCard, LogOut, Check, X, ShieldAlert, Search, Filter, Trash2, AlertTriangle, TrendingUp, DollarSign, PieChart, Calendar, Download, Eye, User, Phone, Hash, FileText, Music, Info } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';
import { DJProfile } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'djs' | 'finance'>('djs');
  const [state, setState] = useState(getAppState());
  const [djToDelete, setDjToDelete] = useState<DJProfile | null>(null);
  const [selectedDJForDetails, setSelectedDJForDetails] = useState<DJProfile | null>(null);

  // DJ Filter states
  const [filterArtisticName, setFilterArtisticName] = useState('');
  const [filterFullName, setFilterFullName] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'pending' | 'approved' | 'rejected'>('all');

  // Finance Filter states
  const [financeSearch, setFinanceSearch] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const handleApproveDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'approved';
    saveAppState(newState);
    setState(newState);
  };

  const handleRejectDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'rejected';
    saveAppState(newState);
    setState(newState);
  };

  const handleDeleteDJ = () => {
    if (!djToDelete) return;
    const newState = { ...state };
    newState.djs = newState.djs.filter(d => d.id !== djToDelete.id);
    saveAppState(newState);
    setState(newState);
    setDjToDelete(null);
  };

  const filteredDJs = useMemo(() => {
    return state.djs.filter(dj => {
      const matchesArtistic = dj.artisticName.toLowerCase().includes(filterArtisticName.toLowerCase());
      const matchesFull = dj.fullName.toLowerCase().includes(filterFullName.toLowerCase());
      const matchesStatus = filterStatus === 'all' || dj.status === filterStatus;
      return matchesArtistic && matchesFull && matchesStatus;
    });
  }, [state.djs, filterArtisticName, filterFullName, filterStatus]);

  const filteredBookings = useMemo(() => {
    return state.bookings.filter(b => {
      const matchesSearch = b.eventType.toLowerCase().includes(financeSearch.toLowerCase()) ||
        b.municipality.toLowerCase().includes(financeSearch.toLowerCase()) ||
        b.province.toLowerCase().includes(financeSearch.toLowerCase());

      const matchesStartDate = startDate ? b.date >= startDate : true;
      const matchesEndDate = endDate ? b.date <= endDate : true;

      return matchesSearch && matchesStartDate && matchesEndDate;
    });
  }, [state.bookings, financeSearch, startDate, endDate]);

  const totalProcessed = filteredBookings.reduce((acc, b) => acc + b.price, 0);
  const totalCommission = filteredBookings.reduce((acc, b) => acc + b.commission, 0);
  const totalDJPayout = filteredBookings.reduce((acc, b) => acc + b.netAmount, 0);

  const exportToCSV = () => {
    const headers = ['Data', 'Evento', 'Local', 'Valor Bruto (Akz)', 'Comissão (Akz)', 'Líquido DJ (Akz)'];
    const rows = filteredBookings.map(b => [
      b.date,
      `"${b.eventType}"`,
      `"${b.municipality}, ${b.province}"`,
      b.price,
      b.commission,
      b.netAmount
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `financeiro_directdj_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex">
      {/* Delete Confirmation Modal */}
      {djToDelete && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setDjToDelete(null)}></div>
          <div className="glass p-8 rounded-3xl max-w-md w-full border border-white/10 relative shadow-2xl animate-in zoom-in duration-200">
            <div className="flex flex-col items-center text-center space-y-4">
              <div className="w-16 h-16 rounded-full bg-red-500/20 flex items-center justify-center mb-2">
                <AlertTriangle size={32} className="text-red-500" />
              </div>
              <h2 className="text-2xl font-bold">Remover DJ?</h2>
              <p className="text-white/60">
                Tem certeza que deseja remover <span className="text-white font-bold">{djToDelete.artisticName}</span>? Esta ação não pode ser desfeita.
              </p>
              <div className="flex gap-4 w-full pt-4">
                <button 
                  onClick={() => setDjToDelete(null)}
                  className="flex-1 py-3 bg-white/5 hover:bg-white/10 rounded-xl font-bold transition-colors">
                  Cancelar
                </button>
                <button 
                  onClick={handleDeleteDJ}
                  className="flex-1 py-3 bg-red-600 hover:bg-red-500 rounded-xl font-bold transition-colors shadow-lg shadow-red-600/20">
                  Confirmar Eliminação
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* DJ Details Modal */}
      {selectedDJForDetails && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-black/85 backdrop-blur-md" onClick={() => setSelectedDJForDetails(null)}></div>
          <div className="glass p-0 rounded-[2.5rem] max-w-4xl w-full border border-white/10 relative shadow-2xl animate-in zoom-in duration-300 overflow-hidden max-h-[90vh] flex flex-col">
            <header className="p-8 border-b border-white/10 flex justify-between items-center bg-white/5">
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-full gradient-bg flex items-center justify-center font-black text-2xl shadow-xl">
                  {selectedDJForDetails.artisticName[0]}
                </div>
                <div>
                  <h2 className="text-2xl font-black">{selectedDJForDetails.artisticName}</h2>
                  <p className="text-white/40 text-sm">Perfil Completo do Artista</p>
                </div>
              </div>
              <button onClick={() => setSelectedDJForDetails(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={24} className="text-white/40" />
              </button>
            </header>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-8">
                {/* Personal & Professional Info */}
                <section className="space-y-6">
                  <h3 className="text-xs font-bold uppercase tracking-widest text-sky-400 flex items-center gap-2">
                    <User size={14} /> Dados Pessoais
                  </h3>
                  <div className="grid gap-4">
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                      <p className="text-[10px] text-white/30 uppercase font-bold mb-1">Nome Completo</p>
                      <p className="font-medium">{selectedDJForDetails.fullName}</p>
                    </div>
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                      <p className="text-[10px] text-white/30 uppercase font-bold mb-1">Bilhete de Identidade (BI)</p>
                      <p className="font-medium font-mono">{selectedDJForDetails.idNumber}</p>
                    </div>
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5 flex justify-between items-center">
                      <div>
                        <p className="text-[10px] text-white/30 uppercase font-bold mb-1">Telefone</p>
                        <p className="font-medium">{selectedDJForDetails.phoneNumber}</p>
                      </div>
                      <Phone size={18} className="text-white/20" />
                    </div>
                  </div>
                </section>

                {/* Finance Section */}
                <section className="space-y-6">
                  <h3 className="text-xs font-bold uppercase tracking-widest text-green-400 flex items-center gap-2">
                    <CreditCard size={14} /> Dados Bancários
                  </h3>
                  <div className="grid gap-4">
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                      <p className="text-[10px] text-white/30 uppercase font-bold mb-1">IBAN de Recebimento</p>
                      <p className="font-medium font-mono break-all">{selectedDJForDetails.iban}</p>
                    </div>
                    <div className="p-4 rounded-2xl bg-sky-500/10 border border-sky-500/20">
                      <div className="flex justify-between items-center">
                        <div>
                          <p className="text-[10px] text-sky-400/60 uppercase font-bold mb-1">Status da Conta</p>
                          <p className="text-sm font-bold capitalize text-sky-400">{selectedDJForDetails.status}</p>
                        </div>
                        <Info size={18} className="text-sky-400/40" />
                      </div>
                    </div>
                  </div>
                </section>
              </div>

              {/* Documents & Gear */}
              <section className="space-y-6">
                <h3 className="text-xs font-bold uppercase tracking-widest text-pink-500 flex items-center gap-2">
                  <FileText size={14} /> Documentação e Equipamento
                </h3>
                <div className="grid md:grid-cols-2 gap-6">
                  <div className="p-6 rounded-3xl bg-white/5 border border-white/5 space-y-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-pink-500/20 rounded-lg text-pink-500">
                        <FileText size={18} />
                      </div>
                      <p className="font-bold">Carteira Profissional</p>
                    </div>
                    <div className="aspect-video rounded-xl bg-black/40 border border-white/5 flex flex-col items-center justify-center text-center p-4">
                      <p className="text-xs text-white/20 italic">Visualização do documento em PDF/PNG</p>
                      <button className="mt-3 px-4 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-bold transition-all">Abrir Documento</button>
                    </div>
                  </div>

                  <div className="p-6 rounded-3xl bg-white/5 border border-white/5 space-y-4">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-orange-500/20 rounded-lg text-orange-500">
                          <Music size={18} />
                        </div>
                        <p className="font-bold">Material de Som</p>
                      </div>
                      <span className={`text-[10px] font-bold px-2 py-1 rounded ${selectedDJForDetails.hasSoundGear ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>
                        {selectedDJForDetails.hasSoundGear ? 'POSSUI' : 'NÃO POSSUI'}
                      </span>
                    </div>
                    {selectedDJForDetails.hasSoundGear ? (
                      <div className="aspect-video rounded-xl bg-black/40 border border-white/5 flex flex-col items-center justify-center text-center p-4">
                         <p className="text-xs text-white/20 italic">Foto do Equipamento</p>
                         <button className="mt-3 px-4 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-bold transition-all">Ver Imagem</button>
                      </div>
                    ) : (
                      <div className="aspect-video rounded-xl bg-white/5 border border-white/5 border-dashed flex flex-col items-center justify-center text-center p-4">
                        <p className="text-xs text-white/20">Sem equipamento registado</p>
                      </div>
                    )}
                  </div>
                </div>
              </section>
            </div>

            <footer className="p-8 border-t border-white/10 bg-black/20 flex gap-4">
              {selectedDJForDetails.status === 'pending' && (
                <>
                  <button onClick={() => { handleApproveDJ(selectedDJForDetails.id); setSelectedDJForDetails(null); }} className="flex-1 py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-2xl transition-all shadow-lg shadow-green-600/20">Aprovar Candidatura</button>
                  <button onClick={() => { handleRejectDJ(selectedDJForDetails.id); setSelectedDJForDetails(null); }} className="flex-1 py-4 bg-red-600/10 hover:bg-red-600/20 text-red-500 font-bold rounded-2xl transition-all border border-red-500/20">Rejeitar</button>
                </>
              )}
              {selectedDJForDetails.status !== 'pending' && (
                <button onClick={() => setSelectedDJForDetails(null)} className="w-full py-4 bg-white/10 hover:bg-white/20 text-white font-bold rounded-2xl transition-all">Fechar Detalhes</button>
              )}
            </footer>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className="w-72 border-r border-white/10 glass p-8 flex flex-col sticky top-0 h-screen">
        <Logo size={32} className="mb-12" />

        <nav className="space-y-2 flex-1">
          <button 
            onClick={() => setActiveTab('djs')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'djs' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <Users size={20} /> DJs Registados
          </button>
          <button 
            onClick={() => setActiveTab('finance')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'finance' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-white/40 hover:bg-white/5'}`}>
            <CreditCard size={20} /> Histórico Financeiro
          </button>
        </nav>

        <div className="pt-8 mt-auto border-t border-white/10">
          <div className="p-4 rounded-xl bg-green-500/10 border border-green-500/20 mb-6">
            <p className="text-xs text-green-200/60 uppercase font-bold tracking-wider mb-1">Lucro no Período</p>
            <p className="text-xl font-black text-green-400">{totalCommission.toLocaleString('pt-AO')} Akz</p>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-3 text-red-400 hover:bg-red-400/10 rounded-xl transition-all font-bold">
            <LogOut size={20} /> Sair
          </button>
        </div>
      </aside>

      {/* Content */}
      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-center mb-12">
          <h1 className="text-3xl font-black">
            {activeTab === 'djs' ? 'Gestão de DJs' : 'Controlo Financeiro'}
          </h1>
          <div className="flex items-center gap-4 bg-white/5 px-4 py-2 rounded-full border border-white/10 text-xs">
            <ShieldAlert size={14} className="text-orange-400" />
            Painel de Segurança Activo
          </div>
        </header>

        {activeTab === 'djs' && (
          <div className="space-y-8">
            {/* Filter Bar */}
            <div className="glass p-6 rounded-2xl border border-white/10 grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Search size={12} /> Nome Artístico
                </label>
                <input 
                  type="text"
                  placeholder="Pesquisar..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterArtisticName}
                  onChange={(e) => setFilterArtisticName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Search size={12} /> Nome Completo
                </label>
                <input 
                  type="text"
                  placeholder="Pesquisar..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterFullName}
                  onChange={(e) => setFilterFullName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-white/40 uppercase flex items-center gap-2">
                  <Filter size={12} /> Status
                </label>
                <select 
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-colors"
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value as any)}
                >
                  <option value="all" className="bg-neutral-900">Todos os Status</option>
                  <option value="pending" className="bg-neutral-900">Pendentes</option>
                  <option value="approved" className="bg-neutral-900">Aprovados</option>
                  <option value="rejected" className="bg-neutral-900">Rejeitados</option>
                </select>
              </div>
            </div>

            {/* List */}
            <div className="grid gap-4">
              {filteredDJs.length > 0 ? (
                filteredDJs.map(dj => (
                  <div key={dj.id} className="glass p-6 rounded-2xl border border-white/10 flex items-center justify-between group hover:border-white/20 transition-all">
                    <div className="flex items-center gap-6">
                      <div className="w-14 h-14 rounded-full gradient-bg flex items-center justify-center font-bold text-xl shadow-lg">
                        {dj.artisticName[0]}
                      </div>
                      <div>
                        <h3 className="font-bold text-lg">{dj.artisticName}</h3>
                        <p className="text-sm text-white/40">{dj.fullName}</p>
                        <div className="flex gap-4 mt-2">
                          <span className="text-[10px] px-2 py-0.5 rounded bg-white/5 border border-white/10 text-white/60">BI: {dj.idNumber}</span>
                          <span className="text-[10px] px-2 py-0.5 rounded bg-white/5 border border-white/10 text-white/60">Tel: {dj.phoneNumber}</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-8">
                      <div className="text-right">
                        <p className="text-xs text-white/40 mb-1">Equipamento</p>
                        <p className={`text-xs font-bold px-2 py-0.5 rounded ${dj.hasSoundGear ? 'bg-sky-500/10 text-sky-400' : 'bg-white/5 text-white/40'}`}>
                          {dj.hasSoundGear ? 'Próprio' : 'Não Possui'}
                        </p>
                      </div>
                      <div className="text-right min-w-[120px]">
                        <p className="text-xs text-white/40 mb-1">Status</p>
                        <span className={`text-[10px] font-black uppercase tracking-wider px-3 py-1 rounded-full ${
                          dj.status === 'approved' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 
                          dj.status === 'pending' ? 'bg-orange-500/10 text-orange-400 border border-orange-500/20' :
                          'bg-red-500/10 text-red-400 border border-red-500/20'
                        }`}>
                          {dj.status === 'approved' ? 'Aprovado' : dj.status === 'pending' ? 'Pendente' : 'Rejeitado'}
                        </span>
                      </div>
                      <div className="flex gap-2 min-w-[180px] justify-end">
                        <button 
                          onClick={() => setSelectedDJForDetails(dj)}
                          title="Ver Detalhes"
                          className="p-3 bg-sky-500/10 text-sky-500 rounded-xl hover:bg-sky-500 hover:text-white transition-all">
                          <Eye size={18} />
                        </button>
                        {dj.status === 'pending' && (
                          <>
                            <button 
                              onClick={() => handleApproveDJ(dj.id)} 
                              title="Aprovar DJ"
                              className="p-3 bg-green-500/10 text-green-500 rounded-xl hover:bg-green-500 hover:text-white transition-all">
                              <Check size={18} />
                            </button>
                            <button 
                              onClick={() => handleRejectDJ(dj.id)}
                              title="Rejeitar DJ"
                              className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                              <X size={18} />
                            </button>
                          </>
                        )}
                        {dj.status !== 'pending' && (
                          <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            {dj.status === 'approved' ? (
                              <button 
                                onClick={() => handleRejectDJ(dj.id)}
                                title="Desativar DJ"
                                className="p-3 bg-white/5 text-white/20 rounded-xl hover:bg-orange-500/20 hover:text-orange-500 transition-all">
                                <X size={18} />
                              </button>
                            ) : (
                              <button 
                                onClick={() => handleApproveDJ(dj.id)}
                                title="Reativar DJ"
                                className="p-3 bg-white/5 text-white/20 rounded-xl hover:bg-green-500/20 hover:text-green-500 transition-all">
                                <Check size={18} />
                              </button>
                            )}
                          </div>
                        )}
                        <button 
                          onClick={() => setDjToDelete(dj)}
                          title="Eliminar DJ"
                          className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-600 hover:text-white transition-all">
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="glass p-20 rounded-2xl border border-white/10 text-center space-y-4">
                  <Users className="w-12 h-12 text-white/10 mx-auto" />
                  <p className="text-white/40 italic">Nenhum DJ encontrado com os filtros selecionados.</p>
                  <button 
                    onClick={() => { setFilterArtisticName(''); setFilterFullName(''); setFilterStatus('all'); }}
                    className="text-sky-400 text-sm hover:underline"
                  >
                    Limpar todos os filtros
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'finance' && (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Financial Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="glass p-6 rounded-3xl border border-white/10 bg-sky-500/5">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-sky-500/20 rounded-2xl text-sky-400">
                    <TrendingUp size={24} />
                  </div>
                  <span className="text-[10px] font-bold text-sky-400 bg-sky-400/10 px-2 py-1 rounded-full">TOTAL PROCESSADO</span>
                </div>
                <h3 className="text-2xl font-black text-white">{totalProcessed.toLocaleString('pt-AO')} Akz</h3>
                <p className="text-xs text-white/40 mt-1">Volume no período filtrado</p>
              </div>

              <div className="glass p-6 rounded-3xl border border-white/10 bg-green-500/5">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-green-500/20 rounded-2xl text-green-400">
                    <PieChart size={24} />
                  </div>
                  <span className="text-[10px] font-bold text-green-400 bg-green-400/10 px-2 py-1 rounded-full">COMISSÕES (10%)</span>
                </div>
                <h3 className="text-2xl font-black text-white">{totalCommission.toLocaleString('pt-AO')} Akz</h3>
                <p className="text-xs text-white/40 mt-1">Lucro bruto no período</p>
              </div>

              <div className="glass p-6 rounded-3xl border border-white/10 bg-purple-500/5">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-purple-500/20 rounded-2xl text-purple-400">
                    <DollarSign size={24} />
                  </div>
                  <span className="text-[10px] font-bold text-purple-400 bg-purple-400/10 px-2 py-1 rounded-full">PAGO AOS DJs</span>
                </div>
                <h3 className="text-2xl font-black text-white">{totalDJPayout.toLocaleString('pt-AO')} Akz</h3>
                <p className="text-xs text-white/40 mt-1">Líquido no período</p>
              </div>
            </div>

            {/* Filters Section */}
            <div className="glass p-6 rounded-3xl border border-white/10 space-y-6">
              <div className="flex flex-col md:flex-row gap-6">
                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Search size={12} /> Pesquisa Geral
                  </label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20" size={14} />
                    <input 
                      type="text" 
                      placeholder="Evento, província ou município..."
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                      value={financeSearch}
                      onChange={(e) => setFinanceSearch(e.target.value)}
                    />
                  </div>
                </div>

                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Calendar size={12} /> Data Inicial
                  </label>
                  <input 
                    type="date"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                  />
                </div>

                <div className="flex-1 space-y-2">
                  <label className="text-[10px] font-bold text-white/40 uppercase flex items-center gap-2">
                    <Calendar size={12} /> Data Final
                  </label>
                  <input 
                    type="date"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm outline-none focus:border-sky-500 transition-all"
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                  />
                </div>

                {(startDate || endDate || financeSearch) && (
                  <div className="flex items-end">
                    <button 
                      onClick={() => { setStartDate(''); setEndDate(''); setFinanceSearch(''); }}
                      className="px-4 py-2 text-[10px] font-bold text-white/40 hover:text-white transition-colors flex items-center gap-2 border border-white/10 rounded-xl bg-white/5 mb-0.5"
                    >
                      <X size={12} /> LIMPAR FILTROS
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* History Table */}
            <div className="space-y-4">
              <div className="flex justify-between items-center px-2">
                <div className="flex items-center gap-4">
                  <h2 className="text-xl font-bold">Histórico de Transações</h2>
                  <p className="text-xs text-white/40">Mostrando {filteredBookings.length} transações</p>
                </div>
                <button 
                  onClick={exportToCSV}
                  disabled={filteredBookings.length === 0}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold text-xs transition-all border border-sky-500/30 bg-sky-500/10 text-sky-400 hover:bg-sky-500 hover:text-white shadow-lg shadow-sky-500/10 ${filteredBookings.length === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'active:scale-95'}`}
                >
                  <Download size={14} /> EXPORTAR CSV
                </button>
              </div>

              <div className="glass rounded-2xl border border-white/10 overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-white/5 text-[10px] font-bold uppercase tracking-wider text-white/40 border-b border-white/10">
                    <tr>
                      <th className="px-6 py-5">Data</th>
                      <th className="px-6 py-5">Evento & Local</th>
                      <th className="px-6 py-5">Valor Bruto</th>
                      <th className="px-6 py-5">Comissão (10%)</th>
                      <th className="px-6 py-5">Líquido DJ</th>
                      <th className="px-6 py-5 text-right">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/10">
                    {filteredBookings.length > 0 ? (
                      filteredBookings.map(booking => (
                        <tr key={booking.id} className="text-sm hover:bg-white/5 transition-colors group">
                          <td className="px-6 py-4">
                            <p className="font-mono text-[10px] text-white/60">{booking.date}</p>
                            <p className="font-mono text-[10px] text-white/20">Ref: #{booking.id}</p>
                          </td>
                          <td className="px-6 py-4">
                            <p className="font-bold text-white">{booking.eventType}</p>
                            <p className="text-[10px] text-white/40">{booking.municipality}, {booking.province}</p>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-white">
                            {booking.price.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-green-400">
                            {booking.commission.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-sky-400">
                            {booking.netAmount.toLocaleString()} <span className="text-[10px] opacity-40">Akz</span>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-green-500/10 text-green-400 rounded-full text-[10px] font-bold uppercase tracking-wider border border-green-500/20">
                              <Check size={10} /> PROCESSADO
                            </span>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan={6} className="px-6 py-20 text-center text-white/20 italic">
                          {(startDate || endDate || financeSearch) 
                            ? 'Nenhum registo financeiro encontrado para os critérios selecionados.' 
                            : 'Nenhum histórico de pagamentos registado até ao momento.'}
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { LayoutDashboard, Users, CreditCard, LogOut, Check, X, ShieldAlert, Search, Filter, Trash2, AlertTriangle, TrendingUp, DollarSign, PieChart, Calendar, Download, Eye, User, Phone, Hash, FileText, Music, Info, Maximize2, ExternalLink } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';
import { DJProfile } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
}

interface MediaViewer {
  type: 'image' | 'document';
  url?: string;
  title: string;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'djs' | 'finance'>('djs');
  const [state, setState] = useState(getAppState());
  const [djToDelete, setDjToDelete] = useState<DJProfile | null>(null);
  const [selectedDJForDetails, setSelectedDJForDetails] = useState<DJProfile | null>(null);
  const [viewingMedia, setViewingMedia] = useState<MediaViewer | null>(null);

  // DJ Filter states
  const [filterArtisticName, setFilterArtisticName] = useState('');
  const [filterFullName, setFilterFullName] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'pending' | 'approved' | 'rejected'>('all');

  // Finance Filter states
  const [financeSearch, setFinanceSearch] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const handleApproveDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'approved';
    saveAppState(newState);
    setState(newState);
  };

  const handleRejectDJ = (id: string) => {
    const newState = { ...state };
    const dj = newState.djs.find(d => d.id === id);
    if (dj) dj.status = 'rejected';
    saveAppState(newState);
    setState(newState);
  };

  const handleDeleteDJ = () => {
    if (!djToDelete) return;
    const newState = { ...state };
    newState.djs = newState.djs.filter(d => d.id !== djToDelete.id);
    saveAppState(newState);
    setState(newState);
    setDjToDelete(null);
  };

  const filteredDJs = useMemo(() => {
    return state.djs.filter(dj => {
      const matchesArtistic = dj.artisticName.toLowerCase().includes(filterArtisticName.toLowerCase());
      const matchesFull = dj.fullName.toLowerCase().includes(filterFullName.toLowerCase());
      const matchesStatus = filterStatus === 'all' || dj.status === filterStatus;
      return matchesArtistic && matchesFull && matchesStatus;
    });
  }, [state.djs, filterArtisticName, filterFullName, filterStatus]);

  const filteredBookings = useMemo(() => {
    return state.bookings.filter(b => {
      const matchesSearch = b.eventType.toLowerCase().includes(financeSearch.toLowerCase()) ||
        b.municipality.toLowerCase().includes(financeSearch.toLowerCase()) ||
        b.province.toLowerCase().includes(financeSearch.toLowerCase());

      const matchesStartDate = startDate ? b.date >= startDate : true;
      const matchesEndDate = endDate ? b.date <= endDate : true;

      return matchesSearch && matchesStartDate && matchesEndDate;
    });
  }, [state.bookings, financeSearch, startDate, endDate]);

  const totalProcessed = filteredBookings.reduce((acc, b) => acc + b.price, 0);
  const totalCommission = filteredBookings.reduce((acc, b) => acc + b.commission, 0);
  const totalDJPayout = filteredBookings.reduce((acc, b) => acc + b.netAmount, 0);

  const exportToCSV = () => {
    const headers = ['Data', 'Evento', 'Local', 'Valor Bruto (Akz)', 'Comissão (Akz)', 'Líquido DJ (Akz)'];
    const rows = filteredBookings.map(b => [
      b.date,
      `"${b.eventType}"`,
      `"${b.municipality}, ${b.province}"`,
      b.price,
      b.commission,
      b.netAmount
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `financeiro_directdj_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex">
      {/* Media Viewer Modal */}
      {viewingMedia && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 md:p-10 animate-in fade-in duration-200">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-xl" onClick={() => setViewingMedia(null)}></div>
          <div className="relative glass w-full max-w-5xl h-full max-h-[85vh] rounded-[2rem] border border-white/10 overflow-hidden flex flex-col shadow-2xl">
            <header className="p-6 border-b border-white/10 flex justify-between items-center bg-black/40">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-white/5 rounded-lg">
                  {viewingMedia.type === 'document' ? <FileText className="text-sky-400" /> : <Music className="text-pink-500" />}
                </div>
                <h3 className="font-bold text-lg">{viewingMedia.title}</h3>
              </div>
              <button onClick={() => setViewingMedia(null)} className="p-3 hover:bg-white/10 rounded-full transition-colors">
                <X size={24} className="text-white/60" />
              </button>
            </header>
            <div className="flex-1 bg-neutral-900 flex items-center justify-center p-8 overflow-auto">
              {viewingMedia.url ? (
                viewingMedia.type === 'image' ? (
                  <img src={viewingMedia.url} alt={viewingMedia.title} className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" />
                ) : (
                  <iframe src={viewingMedia.url} className="w-full h-full rounded-lg border-0 bg-white" title="Document Preview" />
                )
              ) : (
                <div className="text-center space-y-4 max-w-xs">
                  <div className="w-20 h-20 rounded-3xl bg-white/5 flex items-center justify-center mx-auto">
                    <AlertTriangle size={40} className="text-white/20" />
                  </div>
                  <p className="text-white/40 font-medium">O ficheiro original não está disponível nesta versão de demonstração.</p>
                  <p className="text-xs text-white/20">Em ambiente de produção, este espaço carregaria o PDF ou Imagem real enviada pelo DJ.</p>
                </div>
              )}
            </div>
            <footer className="p-6 bg-black/40 border-t border-white/10 flex justify-end gap-4">
               <button onClick={() => setViewingMedia(null)} className="px-6 py-3 bg-white/5 hover:bg-white/10 rounded-xl font-bold transition-all">Fechar Visualização</button>
               <button className="px-6 py-3 gradient-bg rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-pink-500/20 active:scale-95 transition-all">
                 <Download size={18} /> Descarregar Original
               </button>
            </footer>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {djToDelete && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setDjToDelete(null)}></div>
          <div className="glass p-8 rounded-3xl max-w-md w-full border border-white/10 relative shadow-2xl animate-in zoom-in duration-200">
            <div className="flex flex-col items-center text-center space-y-4">
              <div className="w-16 h-16 rounded-full bg-red-500/20 flex items-center justify-center mb-2">
                <AlertTriangle size={32} className="text-red-500" />
              </div>
              <h2 className="text-2xl font-bold">Remover DJ?</h2>
              <p className="text-white/60">
                Tem certeza que deseja remover <span className="text-white font-bold">{djToDelete.artisticName}</span>? Esta ação não pode ser desfeita.
              </p>
              <div className="flex gap-4 w-full pt-4">
                <button 
                  onClick={() => setDjToDelete(null)}
                  className="flex-1 py-3 bg-white/5 hover:bg-white/10 rounded-xl font-bold transition-colors">
                  Cancelar
                </button>
                <button 
                  onClick={handleDeleteDJ}
                  className="flex-1 py-3 bg-red-600 hover:bg-red-500 rounded-xl font-bold transition-colors shadow-lg shadow-red-600/20">
                  Confirmar Eliminação
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* DJ Details Modal */}
      {selectedDJForDetails && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-black/85 backdrop-blur-md" onClick={() => setSelectedDJForDetails(null)}></div>
          <div className="glass p-0 rounded-[2.5rem] max-w-4xl w-full border border-white/10 relative shadow-2xl animate-in zoom-in duration-300 overflow-hidden max-h-[90vh] flex flex-col">
            <header className="p-8 border-b border-white/10 flex justify-between items-center bg-white/5">
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-full gradient-bg flex items-center justify-center font-black text-2xl shadow-xl">
                  {selectedDJForDetails.artisticName[0]}
                </div>
                <div>
                  <h2 className="text-2xl font-black">{selectedDJForDetails.artisticName}</h2>
                  <p className="text-white/40 text-sm">Perfil Completo do Artista</p>
                </div>
              </div>
              <button onClick={() => setSelectedDJForDetails(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={24} className="text-white/40" />
              </button>
            </header>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
