                          <td className="px-6 py-4 text-right"><span className="text-[10px] bg-green-500/10 text-green-400 px-2 py-1 rounded font-bold">PAGO</span></td>
                        </tr>
                      ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

