}

const ANGOLA_PROVINCES = [
  'Bengo', 'Benguela', 'Bié', 'Cabinda', 'Cuando Cubango', 
  'Cuanza Norte', 'Cuanza Sul', 'Cunene', 'Huambo', 'Huíla', 
  'Luanda', 'Lunda Norte', 'Lunda Sul', 'Malanje', 'Moxico', 
  'Namibe', 'Uíge', 'Zaire'
];

export const ClientRequest: React.FC<ClientRequestProps> = ({ onBack }) => {
  const [step, setStep] = useState(1);
  const [availableDjs, setAvailableDjs] = useState<DJProfile[]>([]);
  const [selectedDj, setSelectedDj] = useState<DJProfile | null>(null);

  const [formData, setFormData] = useState({
    eventType: EventType.Aniversario,
    needsGear: false,
    province: 'Luanda',
    municipality: '',
    budget: '',
    date: ''
  });

  const handleSearchDJs = (e: React.FormEvent) => {
    e.preventDefault();
    const state = getAppState();
    const budget = Number(formData.budget);

    // Filter Logic:
    // 1. DJ must be approved
    // 2. If needsGear is true, DJ must have gear
    // 3. DJ's relevant price must be <= budget
    const matched = state.djs.filter(dj => {
      if (dj.status !== 'approved') return false;
      if (formData.needsGear && !dj.hasSoundGear) return false;

      const relevantPrice = formData.needsGear ? dj.priceWithGear : dj.priceDjOnly;
      return relevantPrice <= budget;
    });

    setAvailableDjs(matched);
    setStep(2);
  };

  const handleSelectDj = (dj: DJProfile) => {
    setSelectedDj(dj);
    setStep(3);
  };

  const handlePayment = () => {
    if (!selectedDj) return;
    const state = getAppState();

    // The actual price is the DJ's price (since it fits budget)
    const finalPrice = formData.needsGear ? selectedDj.priceWithGear : selectedDj.priceDjOnly;
    const commission = finalPrice * 0.10; // 10% for the App
    const netAmount = finalPrice - commission; // 90% for the DJ

    const newBooking = {
      id: Math.random().toString(36).substr(2, 9),
      clientId: 'temp-user',
      djId: selectedDj.id,
      djName: selectedDj.artisticName,
      ...formData,
      price: finalPrice,
      budget: Number(formData.budget),
      status: 'paid' as const,
      commission,
      netAmount
    };

    state.bookings.push(newBooking);
    saveAppState(state);
    setStep(4);
  };

  return (
    <div className="min-h-screen p-4 md:p-6 max-w-3xl mx-auto">
      <header className="flex items-center justify-between mb-8 md:mb-12">
        <button onClick={() => step === 1 ? onBack() : setStep(step - 1)} className="flex items-center gap-2 text-white/60 hover:text-white p-2 -ml-2">
          <ArrowLeft size={24} /> <span className="text-lg">Voltar</span>
        </button>
        <Logo size={32} />
      </header>

      {/* STEP 1: EVENT DETAILS & BUDGET */}
      {step === 1 && (
        <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500">
          <div className="text-center px-4">
