export const getAppState = (): AppState => {
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : initialState;
};

export const saveAppState = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const updateDJRating = (djId: string, newRating: number) => {
  const state = getAppState();
  const djIndex = state.djs.findIndex(d => d.id === djId);

  if (djIndex !== -1) {
    const dj = state.djs[djIndex];
    // Calculate new weighted average
    const totalScore = (dj.rating * dj.reviewCount) + newRating;
    const newCount = dj.reviewCount + 1;
    const newAverage = totalScore / newCount;

    state.djs[djIndex] = {
      ...dj,
      rating: parseFloat(newAverage.toFixed(1)),
      reviewCount: newCount
    };

    saveAppState(state);
    return true;
  }
  return false;
};

export const updateAdminSettings = (email: string, password: string) => {
  const state = getAppState();
  state.adminSettings = { email, password };
  saveAppState(state);
};

import React, { useState } from 'react';
import { ArrowLeft, Upload, CheckCircle2, AlertCircle, FileText, ShieldCheck, PhoneCall, Clock, Banknote, MapPin } from 'lucide-react';
import { Logo } from '../components/Logo';
import { getAppState, saveAppState } from '../services/mockData';
import { DJProfile } from '../types';

interface DJRegisterProps {
  onBack: () => void;
}

const ANGOLA_PROVINCES = [
  'Bengo', 'Benguela', 'Bié', 'Cabinda', 'Cuando Cubango', 
  'Cuanza Norte', 'Cuanza Sul', 'Cunene', 'Huambo', 'Huíla', 
  'Luanda', 'Lunda Norte', 'Lunda Sul', 'Malanje', 'Moxico', 
  'Namibe', 'Uíge', 'Zaire'
];

export const DJRegister: React.FC<DJRegisterProps> = ({ onBack }) => {
  const [submitted, setSubmitted] = useState(false);
  const [refId, setRefId] = useState('');
  const [errors, setErrors] = useState<{ iban?: string; price?: string }>({});
  const [formData, setFormData] = useState({
    fullName: '',
    artisticName: '',
    idNumber: '',
    phoneNumber: '',
    province: 'Luanda',
    municipality: '',
    iban: '',
    hasSoundGear: false,
    priceDjOnly: '',
    priceWithGear: ''
  });

  const MIN_PRICE = 100000;
  const MAX_PRICE = 25000000;

  const validateIBAN = (iban: string) => {
    const ibanRegex = /^AO06\d{21}$/;
    if (!iban) return "O IBAN é obrigatório.";
    if (!iban.startsWith('AO06')) return "O IBAN deve começar com AO06.";
    if (iban.length !== 25) return `O IBAN deve ter 25 caracteres (Faltam ${25 - iban.length}).`;
    if (!ibanRegex.test(iban)) return "O IBAN deve conter apenas números após o prefixo AO06.";
    return null;
  };

  const handleIBANChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.toUpperCase().replace(/\s/g, '');
    setFormData({ ...formData, iban: value });
    const error = validateIBAN(value);
    setErrors(prev => ({ ...prev, iban: error || undefined }));
  };

  const validatePrices = () => {
    const djOnly = Number(formData.priceDjOnly);
    if (isNaN(djOnly) || djOnly < MIN_PRICE || djOnly > MAX_PRICE) {
      return `O cache (Apenas DJ) deve estar entre ${MIN_PRICE.toLocaleString()} e ${MAX_PRICE.toLocaleString()} Akz.`;
    }

    if (formData.hasSoundGear) {
      const withGear = Number(formData.priceWithGear);
      if (isNaN(withGear) || withGear < MIN_PRICE || withGear > MAX_PRICE) {
        return `O cache (Com Som) deve estar entre ${MIN_PRICE.toLocaleString()} e ${MAX_PRICE.toLocaleString()} Akz.`;
      }
      if (withGear <= djOnly) {
        return "O valor com som deve ser superior ao valor apenas DJ.";
      }
    }
    return null;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const ibanError = validateIBAN(formData.iban);
    const priceError = validatePrices();

    if (ibanError || priceError) {
      setErrors({ iban: ibanError || undefined, price: priceError || undefined });
      return;
    }

    const generatedRef = `DJ-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
    setRefId(generatedRef);

    const state = getAppState();
    const newDJ: DJProfile = {
      ...formData,
      priceDjOnly: Number(formData.priceDjOnly),
      priceWithGear: formData.hasSoundGear ? Number(formData.priceWithGear) : 0,
      id: Math.random().toString(36).substr(2, 9),
      status: 'pending',
      rating: 0,
      reviewCount: 0
    };
    state.djs.push(newDJ);
    saveAppState(state);
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 animate-in zoom-in duration-500">
        <div className="glass p-8 md:p-12 rounded-[2rem] max-w-2xl w-full border border-white/10 shadow-2xl space-y-8 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-green-500/10 blur-3xl -z-10"></div>

          <div className="text-center space-y-4">
            <div className="w-24 h-24 rounded-full bg-green-500/20 flex items-center justify-center mx-auto mb-6 border border-green-500/30">
              <CheckCircle2 className="w-12 h-12 text-green-500" />
            </div>
            <h2 className="text-4xl font-black">Candidatura Recebida!</h2>
            <p className="text-xl text-white/80">
              Parabéns, <span className="text-sky-400 font-bold">{formData.artisticName}</span>. <br/>O teu perfil foi enviado para análise.
            </p>
            <div className="inline-block px-4 py-2 bg-white/5 rounded-full border border-white/10 text-xs font-mono text-white/40">
              Ref ID: {refId}
            </div>
          </div>
          <div className="pt-4">
            <button onClick={onBack} className="w-full py-5 gradient-bg rounded-2xl font-black text-lg shadow-xl shadow-pink-500/20 active:scale-95 transition-all">
              Voltar à Página Principal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen p-6 max-w-2xl mx-auto">
      <button onClick={onBack} className="flex items-center gap-2 text-white/60 hover:text-white mb-8">
        <ArrowLeft size={20} /> Voltar
      </button>

      <div className="mb-10 text-center">
        <Logo className="justify-center mb-6" size={60} />
        <h1 className="text-3xl font-bold">Torne-se um DJ Oficial</h1>
        <p className="text-white/60">Defina o seu valor e alcance mais clientes.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6 glass p-8 rounded-3xl border border-white/10">
        <div className="grid md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Nome Completo</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500" 
              value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Nome Artístico</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value})} />
          </div>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Bilhete de Identidade (Nº BI)</label>
            <input required className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.idNumber} onChange={e => setFormData({...formData, idNumber: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/60">Telefone</label>
            <input required type="tel" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500"
              value={formData.phoneNumber} onChange={e => setFormData({...formData, phoneNumber: e.target.value})} />
          </div>
        </div>

        {/* Location Fields */}
        <div className="grid md:grid-cols-2 gap-6 pt-4 border-t border-white/5">
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-sm font-medium text-white/60">
              <MapPin size={16} className="text-orange-400" /> Província de Residência
            </label>
            <select className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors"
              value={formData.province} onChange={e => setFormData({...formData, province: e.target.value})}>
              {ANGOLA_PROVINCES.map((prov) => (
                <option key={prov} value={prov} className="bg-neutral-900">{prov}</option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="flex items-center gap-2 text-sm font-medium text-white/60">
               Município
            </label>
            <input required placeholder="Ex: Talatona" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors"
              value={formData.municipality} onChange={e => setFormData({...formData, municipality: e.target.value})} />
          </div>
        </div>

        <div className="space-y-2 pt-4 border-t border-white/5">
          <label className="text-sm font-medium text-white/60">IBAN para Recebimento (25 dígitos)</label>
          <div className="relative">
            <input required placeholder="AO06..." className={`w-full bg-white/5 border ${errors.iban ? 'border-red-500' : 'border-white/10'} rounded-xl px-4 py-3 outline-none focus:border-sky-500 font-mono transition-colors uppercase`}
              value={formData.iban} onChange={handleIBANChange} maxLength={25} />
            {errors.iban && (
              <div className="flex items-center gap-1 mt-2 text-red-400 text-xs animate-in slide-in-from-top-1">
                <AlertCircle size={12} /> <span>{errors.iban}</span>
              </div>
            )}
          </div>
        </div>

        <div className="pt-6 border-t border-white/10 space-y-6">
           <h3 className="font-bold flex items-center gap-2">
            <Banknote size={18} className="text-green-400" /> Definição de Preços (Cache)
          </h3>
          <p className="text-xs text-white/40 -mt-4">
             Defina quanto cobra por evento. O valor deve estar entre 100.000 Akz e 25.000.000 Akz.
          </p>

          <div className="grid md:grid-cols-2 gap-6">
             <div className="space-y-2">
              <label className="text-sm font-medium text-white/60">Cache Apenas DJ (Sem Som)</label>
              <div className="relative">
                <input 
                  type="number" required 
                  min={MIN_PRICE} max={MAX_PRICE}
                  placeholder="Ex: 150000"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-green-500 font-mono"
                  value={formData.priceDjOnly} onChange={e => setFormData({...formData, priceDjOnly: e.target.value})} 
                />
                <span className="absolute right-4 top-3 text-white/20 text-sm">Akz</span>
              </div>
            </div>

             <div className="space-y-2">
              <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-white/60">Cache com Som Completo</label>
                <div className="flex items-center gap-2">
                   <input type="checkbox" id="gear" className="w-4 h-4 rounded accent-sky-500" 
                    checked={formData.hasSoundGear} onChange={e => setFormData({...formData, hasSoundGear: e.target.checked})} />
                   <label htmlFor="gear" className="text-xs cursor-pointer select-none text-sky-400">Tenho Som</label>
                </div>
              </div>

              <div className="relative">
                <input 
                  type="number" 
                  required={formData.hasSoundGear}
                  disabled={!formData.hasSoundGear}
                  min={MIN_PRICE} max={MAX_PRICE}
                  placeholder={formData.hasSoundGear ? "Ex: 300000" : "Não aplicável"}
                  className={`w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-green-500 font-mono ${!formData.hasSoundGear ? 'opacity-30 cursor-not-allowed' : ''}`}
                  value={formData.priceWithGear} onChange={e => setFormData({...formData, priceWithGear: e.target.value})} 
                />
                <span className="absolute right-4 top-3 text-white/20 text-sm">Akz</span>
              </div>
            </div>
          </div>

          {errors.price && (
            <div className="flex items-center gap-1 p-3 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-xs animate-in slide-in-from-top-1">
              <AlertCircle size={14} /> <span>{errors.price}</span>
            </div>
          )}
        </div>

        <div className="space-y-4 pt-4 border-t border-white/10">
          <h3 className="font-bold flex items-center gap-2">
            <FileText size={18} className="text-sky-400" /> Documentação
          </h3>
          <div className="relative border-2 border-dashed border-white/10 rounded-xl p-8 text-center hover:bg-white/5 transition-colors cursor-pointer group">
            <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept=".pdf,.png" />
            <Upload className="mx-auto mb-2 text-white/40 group-hover:text-white" />
            <p className="text-xs text-white/40">Anexar Carteira Profissional (PDF/PNG)</p>
          </div>
        </div>

        <button 
          type="submit" 
          disabled={!!errors.iban}
          className={`w-full py-4 gradient-bg rounded-xl font-bold text-lg shadow-xl shadow-pink-500/20 active:scale-95 transition-all mt-8 ${!!errors.iban ? 'opacity-50 cursor-not-allowed grayscale' : ''}`}
        >
          Submeter Registo
        </button>
      </form>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ArrowLeft, MapPin, Calendar, Music, ShieldCheck, Speaker, Info, CreditCard, Search, Banknote, User, CheckCircle2 } from 'lucide-react';
import { Logo } from '../components/Logo';
import { EventType, DJProfile } from '../types';
import { getAppState, saveAppState } from '../services/mockData';
import { StarRating } from '../components/StarRating';

interface ClientRequestProps {
  onBack: () => void;
}

const ANGOLA_PROVINCES = [
  'Bengo', 'Benguela', 'Bié', 'Cabinda', 'Cuando Cubango', 
  'Cuanza Norte', 'Cuanza Sul', 'Cunene', 'Huambo', 'Huíla', 
  'Luanda', 'Lunda Norte', 'Lunda Sul', 'Malanje', 'Moxico', 
  'Namibe', 'Uíge', 'Zaire'
];

export const ClientRequest: React.FC<ClientRequestProps> = ({ onBack }) => {
  const [step, setStep] = useState(1);
  const [availableDjs, setAvailableDjs] = useState<DJProfile[]>([]);
  const [selectedDj, setSelectedDj] = useState<DJProfile | null>(null);

  const [formData, setFormData] = useState({
    eventType: EventType.Aniversario,
    needsGear: false,
    province: 'Luanda',
    municipality: '',
    budget: '',
    date: ''
  });

  const handleSearchDJs = (e: React.FormEvent) => {
    e.preventDefault();
    const state = getAppState();
    const budget = Number(formData.budget);

    // Filter Logic:
    // 1. DJ must be approved
    // 2. If needsGear is true, DJ must have gear
    // 3. DJ's relevant price must be <= budget
    const matched = state.djs.filter(dj => {
      if (dj.status !== 'approved') return false;
      if (formData.needsGear && !dj.hasSoundGear) return false;

      const relevantPrice = formData.needsGear ? dj.priceWithGear : dj.priceDjOnly;
      return relevantPrice <= budget;
    });

    // Sort Logic: Priority to Location Proximity
    // 1. Same Municipality & Province
    // 2. Same Province
    // 3. Others
    matched.sort((a, b) => {
      const aSameMunicipality = a.municipality.toLowerCase() === formData.municipality.toLowerCase();
      const bSameMunicipality = b.municipality.toLowerCase() === formData.municipality.toLowerCase();
      const aSameProvince = a.province === formData.province;
      const bSameProvince = b.province === formData.province;

      if (aSameMunicipality && !bSameMunicipality) return -1;
      if (!aSameMunicipality && bSameMunicipality) return 1;
      if (aSameProvince && !bSameProvince) return -1;
      if (!aSameProvince && bSameProvince) return 1;
      return 0;
    });

    setAvailableDjs(matched);
    setStep(2);
  };

  const handleSelectDj = (dj: DJProfile) => {
    setSelectedDj(dj);
    setStep(3);
  };

  const handlePayment = () => {
    if (!selectedDj) return;
    const state = getAppState();

    // The actual price is the DJ's price (since it fits budget)
    const finalPrice = formData.needsGear ? selectedDj.priceWithGear : selectedDj.priceDjOnly;
    const commission = finalPrice * 0.10; // 10% for the App
    const netAmount = finalPrice - commission; // 90% for the DJ

    const newBooking = {
      id: Math.random().toString(36).substr(2, 9),
      clientId: 'temp-user',
      djId: selectedDj.id,
      djName: selectedDj.artisticName,
      ...formData,
      price: finalPrice,
      budget: Number(formData.budget),
      status: 'paid' as const,
      commission,
      netAmount
    };

    state.bookings.push(newBooking);
    saveAppState(state);
    setStep(4);
  };

  const isLocationMatch = (dj: DJProfile, type: 'municipality' | 'province') => {
    if (type === 'municipality') {
      return dj.municipality.toLowerCase() === formData.municipality.toLowerCase() && dj.province === formData.province;
    }
    return dj.province === formData.province;
  };

  return (
    <div className="min-h-screen p-4 md:p-6 max-w-3xl mx-auto">
      <header className="flex items-center justify-between mb-8 md:mb-12">
        <button onClick={() => step === 1 ? onBack() : setStep(step - 1)} className="flex items-center gap-2 text-white/60 hover:text-white p-2 -ml-2">
          <ArrowLeft size={24} /> <span className="text-lg">Voltar</span>
        </button>
        <Logo size={32} />
      </header>

      {/* STEP 1: EVENT DETAILS & BUDGET */}
      {step === 1 && (
        <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500">
          <div className="text-center px-4">
            <h1 className="text-3xl md:text-4xl font-bold mb-2">Encontrar DJ</h1>
            <p className="text-white/60 text-sm md:text-base">Diga-nos o que precisa e quanto quer gastar.</p>
          </div>

          <form onSubmit={handleSearchDJs} className="glass p-6 md:p-8 rounded-3xl border border-white/10 space-y-6">
            {/* Event Type & Date */}
            <div className="grid md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                  <Music size={18} className="text-sky-400" /> Tipo de Evento
                </label>
                <select className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors text-base"
                  value={formData.eventType} onChange={e => setFormData({...formData, eventType: e.target.value as EventType})}>
                  {Object.values(EventType).map(type => <option key={type} value={type} className="bg-neutral-900">{type}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                  <Calendar size={18} className="text-pink-500" /> Data do Evento
                </label>
                <input required type="date" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors text-base"
                  value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} />
              </div>
            </div>

            {/* Location */}
            <div className="grid md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                  <MapPin size={18} className="text-orange-400" /> Província
                </label>
                <select className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors text-base"
                  value={formData.province} onChange={e => setFormData({...formData, province: e.target.value})}>
                  {ANGOLA_PROVINCES.map((prov) => (
                    <option key={prov} value={prov} className="bg-neutral-900">{prov}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-2">
                <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                   Município
                </label>
                <input required placeholder="Ex: Talatona" className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors text-base"
                  value={formData.municipality} onChange={e => setFormData({...formData, municipality: e.target.value})} />
              </div>
            </div>

            {/* Gear & Budget */}
            <div className="grid md:grid-cols-2 gap-6 pt-4 border-t border-white/5">
              <div className="space-y-2">
                 <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                  <Speaker size={18} className="text-purple-400" /> Material de Som
                </label>
                <select 
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-sky-500 transition-colors text-base"
                  value={formData.needsGear ? 'yes' : 'no'}
                  onChange={e => setFormData({...formData, needsGear: e.target.value === 'yes'})}
                >
                  <option value="no" className="bg-neutral-900">Não (Apenas DJ)</option>
                  <option value="yes" className="bg-neutral-900">Sim (DJ + Som)</option>
                </select>
              </div>

              <div className="space-y-2">
                <label className="flex items-center gap-2 text-sm font-semibold text-white/80">
                  <Banknote size={18} className="text-green-400" /> Seu Orçamento (Akz)
                </label>
                <input 
                  type="number" required 
                  min="100000"
                  placeholder="Quanto pode pagar?"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 outline-none focus:border-green-500 transition-colors text-base font-mono"
                  value={formData.budget} onChange={e => setFormData({...formData, budget: e.target.value})} 
                />
                <p className="text-[10px] text-white/40">Valor disponível para o serviço</p>
              </div>
            </div>

            <button type="submit" className="w-full py-5 gradient-bg rounded-2xl font-black text-xl shadow-2xl shadow-pink-500/30 active:scale-95 transition-transform mt-4 flex items-center justify-center gap-2">
              <Search size={24} /> Procurar DJs Disponíveis
            </button>
          </form>
        </div>
      )}

      {/* STEP 2: SELECT DJ */}
      {step === 2 && (
        <div className="space-y-6 animate-in slide-in-from-right duration-500">
           <div className="text-center">
            <h1 className="text-3xl font-bold mb-2">DJs Encontrados</h1>
            <p className="text-white/60 text-sm">Baseado no seu orçamento de <span className="text-green-400 font-bold">{Number(formData.budget).toLocaleString()} Akz</span></p>
          </div>

          <div className="grid gap-4">
            {availableDjs.length > 0 ? (
              availableDjs.map(dj => {
                const price = formData.needsGear ? dj.priceWithGear : dj.priceDjOnly;
                return (
                  <div key={dj.id} className="glass p-6 rounded-2xl border border-white/10 flex flex-col md:flex-row items-center justify-between gap-6 hover:border-sky-500/50 transition-all group">
                    <div className="flex items-center gap-4 w-full md:w-auto">
                      <div className="w-16 h-16 rounded-full gradient-bg flex items-center justify-center font-bold text-2xl shadow-lg shrink-0">
                        {dj.artisticName[0]}
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                          <h3 className="font-bold text-lg flex items-center gap-2">
                            {dj.artisticName}
                            <StarRating rating={dj.rating} size={12} />
                          </h3>
                        </div>

                        <p className="text-sm text-white/40 mb-2">{dj.fullName}</p>

                        <div className="flex flex-wrap gap-2">
                          <span className={`text-[10px] flex items-center gap-1 px-2 py-0.5 rounded border ${isLocationMatch(dj, 'municipality') ? 'bg-sky-500/20 text-sky-400 border-sky-500/30' : 'bg-white/5 text-white/40 border-white/10'}`}>
                             <MapPin size={10} /> {dj.municipality}, {dj.province}
                          </span>
                          {formData.needsGear && (
                            <span className="text-[10px] bg-purple-500/10 text-purple-400 border border-purple-500/20 px-2 py-0.5 rounded">Inclui Som</span>
                          )}
                           {isLocationMatch(dj, 'province') && (
                            <span className="text-[10px] bg-green-500/10 text-green-400 border border-green-500/20 px-2 py-0.5 rounded font-bold">Perto de si</span>
                          )}
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center justify-between w-full md:w-auto gap-6 border-t border-white/5 md:border-none pt-4 md:pt-0">
                      <div className="text-right">
                        <p className="text-[10px] text-white/40 uppercase font-bold">Valor do Cache</p>
                        <p className="text-xl font-mono font-bold text-green-400">{price.toLocaleString()} Akz</p>
                      </div>
                      <button 
                        onClick={() => handleSelectDj(dj)}
                        className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-all active:scale-95"
                      >
                        Selecionar
                      </button>
                    </div>
                  </div>
                );
              })
            ) : (
              <div className="text-center py-12 glass rounded-3xl border border-white/10">
                <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4">
                  <User size={40} className="text-white/20" />
                </div>
                <h3 className="text-xl font-bold mb-2">Nenhum DJ Encontrado</h3>
                <p className="text-white/60 max-w-sm mx-auto mb-6">
                  Não encontramos DJs com equipamento (se solicitado) dentro deste orçamento e com disponibilidade.
                </p>
                <button onClick={() => setStep(1)} className="px-8 py-3 bg-white/10 rounded-xl font-bold">
                  Tentar outro valor
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* STEP 3: CONFIRM & PAY */}
      {step === 3 && selectedDj && (
        <div className="space-y-6 md:space-y-8 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h1 className="text-3xl md:text-4xl font-bold mb-2">Confirmar Contratação</h1>
            <p className="text-white/60 text-sm">Pagamento seguro com split automático.</p>
          </div>

          <div className="glass p-6 md:p-8 rounded-3xl border border-white/10 space-y-6 md:space-y-8">
            <div className="space-y-4">
              <h3 className="text-lg font-bold border-b border-white/10 pb-2 flex justify-between items-center">
                <span>Detalhes do Serviço</span>
                <span className="text-xs font-normal bg-sky-500/10 text-sky-400 px-2 py-1 rounded">Ref: #PENDING</span>
              </h3>

              <div className="flex items-center gap-4 bg-white/5 p-4 rounded-xl">
                 <div className="w-12 h-12 rounded-full gradient-bg flex items-center justify-center font-bold text-lg">
                    {selectedDj.artisticName[0]}
                 </div>
                 <div>
                    <p className="text-xs text-white/40 uppercase font-bold">DJ Selecionado</p>
                    <p className="font-bold text-lg">{selectedDj.artisticName}</p>
                 </div>
              </div>

              <div className="space-y-2 text-white/80 text-sm md:text-base pt-2">
                <div className="flex justify-between"><span>Evento</span> <span className="font-medium text-white">{formData.eventType}</span></div>
                <div className="flex justify-between"><span>Data</span> <span className="font-medium text-white">{formData.date}</span></div>
                <div className="flex justify-between"><span>Local</span> <span className="font-medium text-white">{formData.municipality}, {formData.province}</span></div>
                <div className="flex justify-between"><span>Origem do DJ</span> <span className="font-medium text-sky-400">{selectedDj.municipality}, {selectedDj.province}</span></div>
                <div className="flex justify-between"><span>Material</span> <span className="font-medium text-white">{formData.needsGear ? 'Sim (Incluído no preço)' : 'Não (Som do local)'}</span></div>

                <div className="flex justify-between font-bold text-white pt-4 border-t border-white/10 text-xl mt-4">
                  <span>Total a Pagar</span>
                  <span className="text-green-400 font-mono">
                    {(formData.needsGear ? selectedDj.priceWithGear : selectedDj.priceDjOnly).toLocaleString('pt-AO')} Akz
                  </span>
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center gap-4 bg-green-500/10 p-4 rounded-xl border border-green-500/20">
                <ShieldCheck className="text-green-500 shrink-0" />
                <p className="text-xs md:text-sm text-green-200">
                  O valor fica retido na DirectDJ até a confirmação do serviço.
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <button className="p-4 border border-sky-500 bg-sky-500/10 rounded-xl font-bold flex flex-col items-center gap-2 active:scale-95 transition-transform">
                  <CreditCard size={24} className="text-sky-400"/>
                  <span className="text-xs text-center">Multicaixa Express</span>
                </button>
                <button className="p-4 border border-white/10 bg-white/5 rounded-xl font-bold opacity-50 cursor-not-allowed flex flex-col items-center gap-2">
                  <Banknote size={24} />
                  <span className="text-xs text-center">Transferência</span>
                </button>
              </div>
            </div>

            <button onClick={handlePayment} className="w-full py-4 gradient-bg rounded-xl font-bold text-lg shadow-lg shadow-pink-500/20">
              Pagar e Confirmar
            </button>
          </div>
        </div>
      )}

      {/* STEP 4: SUCCESS */}
      {step === 4 && selectedDj && (
        <div className="min-h-[60vh] flex flex-col items-center justify-center space-y-8 animate-in zoom-in duration-500">
          <div className="w-24 h-24 rounded-full bg-green-500 flex items-center justify-center shadow-2xl shadow-green-500/50">
            <CheckCircle2 size={48} className="text-white" />
          </div>
          <div className="text-center space-y-4">
            <h1 className="text-3xl md:text-4xl font-black">Pagamento Confirmado!</h1>
            <p className="text-lg md:text-xl text-white/60">
              <span className="text-white font-bold">{selectedDj.artisticName}</span> foi notificado(a).
            </p>

            <div className="glass p-6 rounded-2xl w-full max-w-sm mx-auto space-y-3 text-left">
              <div className="flex justify-between text-sm border-b border-white/10 pb-2">
                <span className="text-white/40">ID Transação</span>
                <span className="font-mono">#TX-{Math.floor(Math.random() * 999999)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-white/40">Total Pago</span>
                <span className="text-white font-bold">
                   {(formData.needsGear ? selectedDj.priceWithGear : selectedDj.priceDjOnly).toLocaleString('pt-AO')} Akz
                </span>
              </div>
            </div>

            <p className="text-sm text-white/40">O DJ entrará em contacto pelo seu número.</p>
          </div>
          <button onClick={onBack} className="w-full md:w-auto px-12 py-4 gradient-bg rounded-2xl font-bold">Voltar ao Início</button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { LayoutDashboard, Users, CreditCard, LogOut, Check, X, ShieldAlert, Search, Filter, Trash2, AlertTriangle, TrendingUp, DollarSign, PieChart, Calendar, Download, Eye, User, Phone, Hash, FileText, Music, Info, Maximize2, ExternalLink, Settings, Lock, Menu, MapPin } from 'lucide-react';
